map "$http_user_agent::$request_uri" $deny_meta_html {
    default 0;
    "~*meta-externalagent.*::(?!/wp-content/uploads/)" 1;
}

# ==== Bot block: Referer literal sem path (incidente 2026-05-02) ====
# Bot fake-Firefox/142.0 + Chrome/147 envia Referer hardcoded sem trailing slash:
#   Referer: https://concertacaoamazonia.com.br
# Browsers reais sempre incluem path/'/'. 449 reqs com esse padrao no incidente.
# Resposta 444 = close conexao sem responder (poupa banda).
map $http_referer $deny_bot_referer {
    default 0;
    "https://concertacaoamazonia.com.br"     1;
    "http://concertacaoamazonia.com.br"      1;
    "https://www.concertacaoamazonia.com.br" 1;
    "http://www.concertacaoamazonia.com.br"  1;
}

